const body = $input.first().json.body;
const csvText = body.csv_data || '';
const question = body.question || 'Analyse this data and provide key insights';

if (!csvText) {
  return {
    error: 'No CSV data provided',
    usage: 'POST with {"csv_data": "col1,col2\\nval1,val2", "question": "your question"}'
  };
}

// Parse CSV
const lines = csvText.trim().split('\n');
const headers = lines[0].split(',').map(h => h.trim());
const rows = lines.slice(1).map(line => {
  const values = line.split(',').map(v => v.trim());
  const row = {};
  headers.forEach((h, i) => { row[h] = values[i] || ''; });
  return row;
});

// Build summary for Groq
const summary = `Dataset: ${rows.length} rows, ${headers.length} columns
Columns: ${headers.join(', ')}
First 5 rows:
${lines.slice(1, 6).join('\n')}`;

const prompt = `${question}

${summary}

Provide:
1. Key patterns or trends
2. Notable outliers or anomalies  
3. Top 3 actionable insights
4. Data quality observations`;

// Call Groq
const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'https://api.groq.com/openai/v1/chat/completions',
  headers: {
    'Authorization': 'Bearer groqAPIKey',
    'Content-Type': 'application/json'
  },
  body: {
    model: 'llama-3.3-70b-versatile',
    temperature: 0.2,
    messages: [
      {
        role: 'system',
        content: 'You are a senior data analyst. Analyse CSV data and provide clear, actionable insights. Be specific with numbers and percentages where possible.'
      },
      {
        role: 'user',
        content: prompt
      }
    ]
  },
  json: true
});

return {
  question: question,
  rows_analysed: rows.length,
  columns: headers,
  insights: response.choices[0].message.content,
  analysed_at: new Date().toISOString()
};
